import React from 'react';
import BookList from '../../components/books/BookList/BookList'; // Fixed path
import { sampleBooks } from '../../utils/sampleData';
import './Home.css';

const Home = () => {
  const popularTopics = [
    { name: "Data Science", learners: "4M+" },
    { name: "Python", learners: "48.8M+" },
    { name: "Machine Learning", learners: "9M+" },
    { name: "Deep Learning", learners: "2M+" },
    { name: "Artificial Intelligence (AI)", learners: "4M+" },
    { name: "Statistics", learners: "1M+" }
  ];

  const publicBooks = sampleBooks.filter(book => book.isPublic);

  return (
    <div className="home">
      <section className="hero">
        <div className="hero-content">
          <h1>All the skills you need in one place</h1>
          <p>From critical skills to technical topics, our Library supports your professional development.</p>
        </div>
      </section>

      <section className="popular-topics">
        <h2>Popular Topics</h2>
        <div className="topics-grid">
          {popularTopics.map((topic, index) => (
            <div key={index} className="topic-card">
              <h3>{topic.name}</h3>
              <p>{topic.learners} learners</p>
            </div>
          ))}
        </div>
      </section>

      <section className="featured-books">
        <h2>Featured Books</h2>
        <BookList books={publicBooks} />
      </section>

      <section className="cta-section">
        <div className="cta-content">
          <h2>Unlock your career potential in the AI era</h2>
          <p>Level up with AI and other cutting-edge skills to reach your career goals.</p>
          <button className="cta-button">Get Personal Plan</button>
        </div>
      </section>
    </div>
  );
};

export default Home;
